function Navbar() {
  return (
    <nav
      style={{
        backgroundColor: "#6C63FF",
        padding: "15px",
        color: "white",
        textAlign: "center",
        fontSize: "24px",
        fontWeight: "bold",
      }}
    >
      Smart Study Planner 📚
    </nav>
  );
}

export default Navbar;
